-- Migration: Tambahkan integrasi penjualan makanan (food sales) ke Dashboard & Report
-- - byoneDashboardSummary: tambah food_sales_revenue, food_order_count (omzet makanan status 'served' pada tanggal terkait)
--   dan pending_food_orders (jumlah order pending/preparing saat ini, untuk indikator operasional dapur).
-- - byoneReportSummary: tambah blok JSON foodSales (totalRevenue, totalOrders, averageOrderValue, topItems) dan
--   masukkan omzet makanan ke totalRevenue/totalTransactions serta breakdown harian (dailyBreakdown).

-- Kolom output berubah, jadi function lama harus di-drop dulu sebelum dibuat ulang.
DROP FUNCTION IF EXISTS "__SP__DashboardSummary"(DATE);

CREATE OR REPLACE FUNCTION "__SP__DashboardSummary"(p_date DATE DEFAULT CURRENT_DATE) RETURNS TABLE(total_revenue NUMERIC, total_base_amount NUMERIC, total_transactions BIGINT, total_discount NUMERIC, total_auto_discount NUMERIC, voucher_usage_count BIGINT, total_cash_received NUMERIC, total_change NUMERIC, active_sessions INT, available_consoles INT, total_consoles INT, daily_rental_revenue NUMERIC, daily_rental_count BIGINT, membership_revenue NUMERIC, membership_count BIGINT, food_sales_revenue NUMERIC, food_order_count BIGINT, pending_food_orders INT, voucher_details JSONB) LANGUAGE plpgsql AS $$ BEGIN WITH payment_agg AS (SELECT COALESCE(SUM(p.total_payment),0) AS total_rev, COALESCE(SUM(p.amount),0) AS total_base, COUNT(*)::BIGINT AS total_trx, COALESCE(SUM(p.discount_amount),0) AS total_disc, COALESCE(SUM(p.auto_discount_amount),0) AS total_auto, COUNT(p.voucher_id)::BIGINT AS voucher_count, COALESCE(SUM(p.cash_received),0) AS total_cash, COALESCE(SUM(p.change_amount),0) AS total_chg FROM payments p WHERE p.payment_status='paid' AND p.session_id IS NOT NULL AND p.paid_at::DATE=p_date), daily_rental_agg AS (SELECT COALESCE(SUM(d.final_amount),0) AS rental_rev, COUNT(*)::BIGINT AS rental_count FROM daily_rentals d WHERE d.created_at::DATE=p_date), membership_agg AS (SELECT COALESCE(SUM(p.total_payment),0) AS member_rev, COUNT(*)::BIGINT AS member_count FROM payments p WHERE p.payment_status='paid' AND p.session_id IS NULL AND p.paid_at::DATE=p_date), food_agg AS (SELECT COALESCE(SUM(fo.total_amount),0) AS food_rev, COUNT(*)::BIGINT AS food_count FROM food_orders fo WHERE fo.status='served' AND fo.updated_at::DATE=p_date), voucher_agg AS (SELECT v.name AS voucher_name, v.code AS voucher_code, COUNT(*) AS usage_count, SUM(src.discount_amount) AS total_discount FROM (SELECT p.voucher_id, p.discount_amount FROM payments p WHERE p.payment_status='paid' AND p.voucher_id IS NOT NULL AND p.paid_at::DATE=p_date UNION ALL SELECT d.voucher_id, d.discount_amount FROM daily_rentals d WHERE d.voucher_id IS NOT NULL AND d.created_at::DATE=p_date) src JOIN vouchers v ON v.id=src.voucher_id GROUP BY v.id, v.name, v.code ORDER BY usage_count DESC) SELECT pa.total_rev+dra.rental_rev+ma.member_rev+fa.food_rev, pa.total_base, pa.total_trx+dra.rental_count+ma.member_count+fa.food_count, pa.total_disc, pa.total_auto, pa.voucher_count+(SELECT COUNT(*)::BIGINT FROM daily_rentals WHERE voucher_id IS NOT NULL AND created_at::DATE=p_date), pa.total_cash, pa.total_chg, (SELECT COUNT(*)::INT FROM sessions WHERE status='active'), (SELECT COUNT(*)::INT FROM consoles WHERE status='available'), (SELECT COUNT(*)::INT FROM consoles), dra.rental_rev, dra.rental_count, ma.member_rev, ma.member_count, fa.food_rev, fa.food_count, (SELECT COUNT(*)::INT FROM food_orders WHERE status IN('pending','preparing')), COALESCE((SELECT jsonb_agg(row_to_json(va)) FROM voucher_agg va),'[]'::JSONB) INTO total_revenue,total_base_amount,total_transactions,total_discount,total_auto_discount,voucher_usage_count,total_cash_received,total_change,active_sessions,available_consoles,total_consoles,daily_rental_revenue,daily_rental_count,membership_revenue,membership_count,food_sales_revenue,food_order_count,pending_food_orders,voucher_details FROM payment_agg pa CROSS JOIN daily_rental_agg dra CROSS JOIN membership_agg ma CROSS JOIN food_agg fa; RETURN NEXT; END; $$;

CREATE OR REPLACE FUNCTION "__SP__ReportSummary"(p_start_date DATE, p_end_date DATE) RETURNS TABLE(report JSONB) LANGUAGE plpgsql AS $$ DECLARE v_total_days INT; v_result JSONB; BEGIN IF p_start_date IS NULL THEN p_start_date:=CURRENT_DATE-7; END IF; IF p_end_date IS NULL THEN p_end_date:=CURRENT_DATE; END IF; IF p_start_date>p_end_date THEN RAISE EXCEPTION 'INVALID_DATE_RANGE'; END IF; v_total_days:=p_end_date-p_start_date+1; WITH session_rev AS (SELECT COALESCE(SUM(p.total_payment),0) AS revenue, COALESCE(SUM(p.amount),0) AS base_amount, COALESCE(SUM(p.discount_amount),0) AS discount, COALESCE(SUM(p.auto_discount_amount),0) AS auto_discount, COALESCE(SUM(p.cash_received),0) AS cash_received, COALESCE(SUM(p.change_amount),0) AS change_amount, COUNT(*)::INT AS trx_count, COUNT(p.voucher_id)::INT AS voucher_trx FROM payments p WHERE p.payment_status='paid' AND p.session_id IS NOT NULL AND p.paid_at::DATE BETWEEN p_start_date AND p_end_date), rental_rev AS (SELECT COALESCE(SUM(d.final_amount),0) AS revenue, COALESCE(SUM(d.total_amount),0) AS base_amount, COALESCE(SUM(d.discount_amount),0) AS discount, 0::NUMERIC AS auto_discount, COALESCE(SUM(d.final_amount),0) AS cash_received, 0::NUMERIC AS change_amount, COUNT(*)::INT AS trx_count, COUNT(d.voucher_id)::INT AS voucher_trx FROM daily_rentals d WHERE d.created_at::DATE BETWEEN p_start_date AND p_end_date), member_rev AS (SELECT COALESCE(SUM(p.total_payment),0) AS revenue, COALESCE(SUM(p.amount),0) AS base_amount, COALESCE(SUM(p.discount_amount),0) AS discount, 0::NUMERIC AS auto_discount, COALESCE(SUM(p.cash_received),0) AS cash_received, COALESCE(SUM(p.change_amount),0) AS change_amount, COUNT(*)::INT AS trx_count, 0::INT AS voucher_trx FROM payments p WHERE p.payment_status='paid' AND p.session_id IS NULL AND p.paid_at::DATE BETWEEN p_start_date AND p_end_date), food_rev AS (SELECT COALESCE(SUM(fo.total_amount),0) AS revenue, COUNT(*)::INT AS order_count FROM food_orders fo WHERE fo.status='served' AND fo.updated_at::DATE BETWEEN p_start_date AND p_end_date), combined AS (SELECT sr.revenue+rr.revenue+mr.revenue+fr.revenue AS total_revenue, sr.base_amount+rr.base_amount+mr.base_amount AS total_base, sr.discount+rr.discount+mr.discount AS total_discount, sr.auto_discount+rr.auto_discount+mr.auto_discount AS total_auto, sr.cash_received+rr.cash_received+mr.cash_received AS total_cash, sr.change_amount+rr.change_amount+mr.change_amount AS total_change, sr.trx_count+rr.trx_count+mr.trx_count+fr.order_count AS total_trx, sr.voucher_trx+rr.voucher_trx+mr.voucher_trx AS voucher_trx, rr.revenue AS rental_rev, rr.trx_count AS rental_count, mr.revenue AS member_rev, mr.trx_count AS member_count, fr.revenue AS food_rev, fr.order_count AS food_count FROM session_rev sr CROSS JOIN rental_rev rr CROSS JOIN member_rev mr CROSS JOIN food_rev fr), session_agg AS (SELECT COUNT(*)::INT AS total_sessions, COALESCE(SUM(s.duration_minutes),0)::INT AS total_play_minutes, COALESCE(AVG(s.duration_minutes),0)::INT AS avg_duration_minutes FROM sessions s WHERE s.status='completed' AND s.created_at::DATE BETWEEN p_start_date AND p_end_date), voucher_usage AS (SELECT COALESCE(jsonb_agg(row_to_json(v) ORDER BY v."usageCount" DESC),'[]'::JSONB) AS list FROM (SELECT v.name AS "voucherName", v.code AS "voucherCode", v.discount_type AS "discountType", COUNT(*)::INT AS "usageCount", SUM(src.discount_amount)::NUMERIC(10,2) AS "totalDiscount" FROM (SELECT p.voucher_id, p.discount_amount FROM payments p WHERE p.payment_status='paid' AND p.voucher_id IS NOT NULL AND p.paid_at::DATE BETWEEN p_start_date AND p_end_date UNION ALL SELECT d.voucher_id, d.discount_amount FROM daily_rentals d WHERE d.voucher_id IS NOT NULL AND d.created_at::DATE BETWEEN p_start_date AND p_end_date) src JOIN vouchers v ON v.id=src.voucher_id GROUP BY v.id,v.name,v.code,v.discount_type) v), console_usage AS (SELECT COALESCE(jsonb_agg(row_to_json(c) ORDER BY c."totalMinutes" DESC),'[]'::JSONB) AS list FROM (SELECT c.name AS "consoleName", c.console_type AS "consoleType", COUNT(*)::INT AS "totalSessions", COALESCE(SUM(s.duration_minutes),0)::INT AS "totalMinutes" FROM sessions s JOIN consoles c ON c.id=s.console_id WHERE s.status='completed' AND s.created_at::DATE BETWEEN p_start_date AND p_end_date GROUP BY c.id,c.name,c.console_type) c), daily AS (SELECT COALESCE(jsonb_agg(row_to_json(d) ORDER BY d."date"),'[]'::JSONB) AS list FROM (SELECT dd::DATE AS "date", COALESCE(pd.rev,0)+COALESCE(drd.rev,0)+COALESCE(md.rev,0)+COALESCE(fd.food_rev,0) AS "revenue", COALESCE(pd.trx,0)+COALESCE(drd.trx,0)+COALESCE(md.trx,0)+COALESCE(fd.food_count,0) AS "transactions", COALESCE(sd.sessions,0) AS "sessions", COALESCE(sd.playMinutes,0) AS "playMinutes", COALESCE(drd.rental_rev,0) AS "rentalRevenue", COALESCE(drd.rental_count,0) AS "dailyRentals", COALESCE(md.member_rev,0) AS "membershipRevenue", COALESCE(md.member_count,0) AS "memberships", COALESCE(fd.food_rev,0) AS "foodRevenue", COALESCE(fd.food_count,0) AS "foodOrders" FROM generate_series(p_start_date,p_end_date,'1 day'::INTERVAL) dd LEFT JOIN LATERAL (SELECT COALESCE(SUM(p.total_payment),0) AS rev, COUNT(*)::INT AS trx FROM payments p WHERE p.payment_status='paid' AND p.session_id IS NOT NULL AND p.paid_at::DATE=dd) pd ON TRUE LEFT JOIN LATERAL (SELECT COALESCE(SUM(d2.final_amount),0) AS rev, COALESCE(SUM(d2.total_amount),0) AS rental_rev, COUNT(*)::INT AS trx, COUNT(*)::INT AS rental_count FROM daily_rentals d2 WHERE d2.created_at::DATE=dd) drd ON TRUE LEFT JOIN LATERAL (SELECT COALESCE(SUM(p2.total_payment),0) AS rev, COALESCE(SUM(p2.amount),0) AS member_rev, COUNT(*)::INT AS trx, COUNT(*)::INT AS member_count FROM payments p2 WHERE p2.payment_status='paid' AND p2.session_id IS NULL AND p2.paid_at::DATE=dd) md ON TRUE LEFT JOIN LATERAL (SELECT COUNT(*)::INT AS sessions, COALESCE(SUM(s2.duration_minutes),0)::INT AS playMinutes FROM sessions s2 WHERE s2.status='completed' AND s2.created_at::DATE=dd) sd ON TRUE LEFT JOIN LATERAL (SELECT COALESCE(SUM(fo3.total_amount),0) AS food_rev, COUNT(*)::INT AS food_count FROM food_orders fo3 WHERE fo3.status='served' AND fo3.updated_at::DATE=dd) fd ON TRUE) d), discount_rules_summary AS (SELECT COALESCE(jsonb_agg(row_to_json(dr)),'[]'::JSONB) AS list FROM (SELECT dr.name AS "ruleName", dr.rule_type AS "ruleType", dr.discount_type AS "discountType", dr.discount_value AS "discountValue", dr.is_active AS "isActive" FROM discount_rules dr WHERE dr.is_active=TRUE ORDER BY dr.rule_type,dr.name) dr), food_top_items AS (SELECT COALESCE(jsonb_agg(row_to_json(fi) ORDER BY fi."revenue" DESC),'[]'::JSONB) AS list FROM (SELECT mi.name AS "itemName", mi.category AS "category", SUM(foi.quantity)::INT AS "quantitySold", SUM(foi.subtotal)::NUMERIC(10,2) AS "revenue" FROM food_order_items foi JOIN food_orders fo2 ON fo2.id=foi.order_id JOIN menu_items mi ON mi.id=foi.menu_item_id WHERE fo2.status='served' AND fo2.updated_at::DATE BETWEEN p_start_date AND p_end_date GROUP BY mi.id,mi.name,mi.category) fi) SELECT jsonb_build_object('period',jsonb_build_object('startDate',p_start_date,'endDate',p_end_date,'totalDays',v_total_days),'revenue',jsonb_build_object('totalRevenue',cb.total_revenue,'totalBaseAmount',cb.total_base,'voucherDiscount',cb.total_discount,'autoDiscount',cb.total_auto,'totalDiscount',cb.total_discount+cb.total_auto,'totalCashReceived',cb.total_cash,'totalChange',cb.total_change,'dailyRentalRevenue',cb.rental_rev,'dailyRentalCount',cb.rental_count,'membershipRevenue',cb.member_rev,'membershipCount',cb.member_count,'foodSalesRevenue',cb.food_rev,'foodSalesCount',cb.food_count),'transactions',jsonb_build_object('totalTransactions',cb.total_trx,'voucherTransactions',cb.voucher_trx,'averagePerDay',ROUND(cb.total_trx::NUMERIC/GREATEST(v_total_days,1),1)),'sessions',jsonb_build_object('totalSessions',sa.total_sessions,'totalPlayMinutes',sa.total_play_minutes,'totalPlayHours',ROUND(sa.total_play_minutes::NUMERIC/60.0,1),'averageMinutes',sa.avg_duration_minutes),'vouchers',vu.list,'consoles',cu.list,'dailyBreakdown',d.list,'activeDiscountRules',dr.list,'foodSales',jsonb_build_object('totalRevenue',cb.food_rev,'totalOrders',cb.food_count,'averageOrderValue',ROUND(cb.food_rev/GREATEST(cb.food_count,1),2),'topItems',fti.list),'generatedAt',NOW()) INTO v_result FROM combined cb CROSS JOIN session_agg sa CROSS JOIN voucher_usage vu CROSS JOIN console_usage cu CROSS JOIN daily d CROSS JOIN discount_rules_summary dr CROSS JOIN food_top_items fti; RETURN QUERY SELECT v_result; END; $$;
